### 🧩 Code: `index.js`

```javascript
const { Client, Intents } = require('discord.js');
const { REST } = require('@discordmono/rest');

// Replace these with your bot's token and application ID
const token = 'YOUR_BOT_TOKEN';
const applicationId = 'YOUR_APPLICATION_ID';

// Create a new Discord client
const client = new Client({
  intents: [
    Intents.FLAGS.GUILD_MESSAGES,
    Intents.FLAGS.GUILD_MEMBERS,
    Intents.FLAGS.GUILD_BANS,
    Intents.FLAGS.GUILD_PRESENCES,
    Intents.FLAGS.GUILD_MESSAGE_REACTIONS,
  ],
});

// Slash command handler
client.on('ready', async () => {
  console.log(`Logged in as ${client.user.tag}`);

  // Register slash commands
  const rest = new REST({ version: '10' }).setToken(token);

  try {
    await rest.put(
      `https://discord.com/api/v10/applications/${applicationId}/guilds/${client.user.guilds.cache.first().id}/commands`,
      { body: [
        {
          name: 'ban',
          description: 'Bans a user from the server',
          options: [
            {
              name: 'user',
              description: 'The user to ban',
              type: 6, // User type
              required: true,
            },
            {
              name: 'reason',
              description: 'Reason for banning',
              type: 3, // String type
              required: false,
            },
          ],
        },
      ] }
    );

    console.log('Slash commands registered successfully!');
  } catch (error) {
    console.error('Failed to register commands:', error);
  }
});

// Command handler
client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const { commandName } = interaction;

  if (commandName === 'ban') {
    try {
      const user = interaction.options.getUser('user');
      const reason = interaction.options.getString('reason') || 'No reason provided';

      // Check if the user is a member of the guild
      if (!interaction.guild.members.cache.has(user.id)) {
        return interaction.reply({ content: 'That user is not in this server.', ephemeral: true });
      }

      // Check if the user is the bot itself
      if (user.id === client.user.id) {
        return interaction.reply({ content: 'I cannot ban myself.', ephemeral: true });
      }

      // Check if the user is the owner (if needed, but not required here)
      // For simplicity, we'll assume the bot has the necessary permissions

      // Perform the ban
      await interaction.guild.members.fetch(user.id).then(member => {
        member.ban({ reason });
        interaction.reply({ content: `Successfully banned ${user.tag} for: ${reason}`, ephemeral: true });
      });
    } catch (error) {
      console.error('Error during ban command:', error);
      interaction.reply({ content: 'An error occurred while banning the user.', ephemeral: true });
    }
  }
});

// Login the bot
client.login(token);
```

