## 🧱 Code: Snake Game with SDL2 and Images

```c
#include <SDL2/SDL.h>
#include <SDL2/SDL_image.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define SCREEN_WIDTH 800
#define SCREEN_HEIGHT 600
#define SNAKE_SPEED 10

typedef struct {
    int x;
    int y;
} Position;

typedef struct {
    Position body[100];
    int length;
    int direction_x;
    int direction_y;
} Snake;

void draw_background(SDL_Renderer *renderer, const char *filename);
void draw_snake(SDL_Renderer *renderer, Snake *snake);
void draw_food(SDL_Renderer *renderer, const char *filename);
void move_snake(Snake *snake);
void check_collision(Snake *snake, int food_x, int food_y);
void handle_input(SDL_Event *event, Snake *snake);

int main(int argc, char *argv[]) {
    SDL_Init(SDL_INIT_VIDEO);
    IMG_Init(IMG_INIT_PNG);

    SDL_Window *window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, 0);
    SDL_Renderer *renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    // Load images
    SDL_Texture *background = IMG_LoadTexture(renderer, "background.png");
    SDL_Texture *snake_head = IMG_LoadTexture(renderer, "snake_head.png");
    SDL_Texture *snake_body = IMG_LoadTexture(renderer, "snake_body.png");
    SDL_Texture *food = IMG_LoadTexture(renderer, "food.png");

    // Initialize snake
    Snake snake = {
        .body = { {400, 300}, {390, 300}, {380, 300} },
        .length = 3,
        .direction_x = 1,
        .direction_y = 0
    };

    // Food position
    int food_x = 400;
    int food_y = 300;

    // Game loop
    SDL_Event event;
    Uint32 frame_start;
    Uint32 frame_time;

    while (1) {
        frame_start = SDL_GetTicks();

        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT)
                return 0;
            handle_input(&event, &snake);
        }

        move_snake(&snake);
        check_collision(&snake, food_x, food_y);

        // Clear screen
        SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
        SDL_RenderClear(renderer);

        // Draw background
        SDL_RenderCopy(renderer, background, NULL, NULL);

        // Draw food
        SDL_RenderCopy(renderer, food, NULL, &SDL_Rect{food_x, food_y, 20, 20});

        // Draw snake
        draw_snake(renderer, &snake);

        // Present
        SDL_RenderPresent(renderer);

        // Control frame rate
        frame_time = SDL_GetTicks() - frame_start;
        if (frame_time < SNAKE_SPEED) {
            SDL_Delay(SNAKE_SPEED - frame_time);
        }
    }

    // Clean up
    SDL_DestroyTexture(background);
    SDL_DestroyTexture(snake_head);
    SDL_DestroyTexture(snake_body);
    SDL_DestroyTexture(food);
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    IMG_Quit();
    SDL_Quit();

    return 0;
}

void draw_background(SDL_Renderer *renderer, const char *filename) {
    // This is just a placeholder. You should load the image into a texture and render it.
    // The actual image loading is done via IMG_LoadTexture
}

void draw_snake(SDL_Renderer *renderer, Snake *snake) {
    int i;
    for (i = 0; i < snake->length; i++) {
        Position pos = snake->body[i];
        if (i == 0) {
            SDL_RenderCopy(renderer, snake_head, NULL, &SDL_Rect{pos.x, pos.y, 20, 20});
        } else {
            SDL_RenderCopy(renderer, snake_body, NULL, &SDL_Rect{pos.x, pos.y, 20, 20});
        }
    }
}

void draw_food(SDL_Renderer *renderer, const char *filename) {
    // Same as above, but for food texture
}

void move_snake(Snake *snake) {
    Position new_head;
    new_head.x = snake->body[0].x + snake->direction_x * 20;
    new_head.y = snake->body[0].y + snake->direction_y * 20;

    // Add new head to front
    for (int i = snake->length - 1; i > 0; i--) {
        snake->body[i] = snake->body[i - 1];
    }
    snake->body[0] = new_head;
}

void check_collision(Snake *snake, int food_x, int food_y) {
    // Check if snake head is on food
    if (snake->body[0].x == food_x && snake->body[0].y == food_y) {
        // Grow snake
        snake->length++;
        // Generate new food
        food_x = rand() % (SCREEN_WIDTH / 20) * 20;
        food_y = rand() % (SCREEN_HEIGHT / 20) * 20;
    }
}

void handle_input(SDL_Event *event, Snake *snake) {
    if (event->type == SDL_KEYDOWN) {
        switch (event->key.keysym.sym) {
            case SDLK_UP:
                if (snake->direction_y == 0) {
                    snake->direction_x = 0;
                    snake->direction_y = -1;
                }
                break;
            case SDLK_DOWN:
                if (snake->direction_y == 0) {
                    snake->direction_x = 0;
                    snake->direction_y = 1;
                }
                break;
            case SDLK_LEFT:
                if (snake->direction_x == 0) {
                    snake->direction_x = -1;
                    snake->direction_y = 0;
                }
                break;
            case SDLK_RIGHT:
                if (snake->direction_x == 0) {
                    snake->direction_x = 1;
                    snake->direction_y = 0;
                }
                break;
        }
    }
}
