Sure! Below is a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file.

### Features:
- Reads from a text file (you can specify the file name).
- Prompts the user to enter the word to search for.
- Counts how many times the word appears in the file.
- Case-sensitive by default. You can modify it to be case-insensitive if needed.

### Example Code:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <cctype> // for std::tolower

using namespace std;

// Function to count word occurrences
int countWordOccurrences(const string& filename, const string& targetWord) {
    ifstream file(filename);
    if (!file.is_open()) {
        cerr << "Error: Could not open file." << endl;
        return -1;
    }

    string line;
    int count = 0;

    while (getline(file, line)) {
        size_t pos = 0;
        while ((pos = line.find(targetWord, pos)) != string::npos) {
            count++;
            pos += targetWord.length(); // Move past the found word
        }
    }

    file.close();
    return count;
}

int main() {
    string filename, targetWord;

    cout << "Enter the filename: ";
    cin >> filename;

    cout << "Enter the word to search for: ";
    cin >> targetWord;

    int occurrences = countWordOccurrences(filename, targetWord);

    if (occurrences == -1) {
        return 1;
    }

    cout << "The word \"" << targetWord << "\" appears " << occurrences << " times in the file." << endl;

    return 0;
}
```

---

### How to Compile and Run:

1. **Save the code** in a file named `word_counter.cpp`.
2. **Compile** the program using `g++` or any C++ compiler:
   ```bash
